// ===== 场景配置 =====

interface GuideLine {
  label: string;
  expr: string;
}

interface InputStep {
  label: string;
  answer: number;
  unit: string;
}

interface SceneConfig {
  id: string;
  icon: string;
  title: string;
  question: string;
  guide: GuideLine[];
  inputs: InputStep[];
  svg: React.ReactNode;
}

const SCENES: SceneConfig[] = [
  {
    id: "vacation",
    icon: "🏖️",
    title: "放假天数",
    question: "7月15日放暑假，8月31日开学，暑假有多少天？",
    guide: [
      { label: "7月", expr: "31 - 15 + 1 = 17 天" },
      { label: "8月", expr: "31 天" },
      { label: "总计", expr: "17 + 31 = 48 天" },
    ],
    inputs: [
      { label: "7月有多少天？", answer: 17, unit: "天" },
      { label: "8月有多少天？", answer: 31, unit: "天" },
      { label: "暑假一共多少天？", answer: 48, unit: "天" },
    ],
    svg: <BeachSVG />,
  },
  {
    id: "birthday",
    icon: "🎂",
    title: "生日倒计时",
    question: "今天是7月15日，小明的生日是10月3日，还有多少天？",
    guide: [
      { label: "7月剩余", expr: "31 - 15 = 16 天" },
      { label: "8月", expr: "31 天" },
      { label: "9月", expr: "30 天" },
      { label: "10月", expr: "3 天" },
      { label: "总计", expr: "16 + 31 + 30 + 3 = 80 天" },
    ],
    inputs: [{ label: "距离生日还有多少天？", answer: 80, unit: "天" }],
    svg: <CakeSVG />,
  },
  {
    id: "school",
    icon: "📚",
    title: "上学天数",
    question: "9月1日开学，1月20日期末考试，一学期有多少天？",
    guide: [
      { label: "9月", expr: "30 天" },
      { label: "10月", expr: "31 天" },
      { label: "11月", expr: "30 天" },
      { label: "12月", expr: "31 天" },
      { label: "1月", expr: "20 天" },
      { label: "总计", expr: "30 + 31 + 30 + 31 + 20 = 142 天" },
    ],
    inputs: [{ label: "这一学期一共有多少天？", answer: 142, unit: "天" }],
    svg: <SchoolSVG />,
  },
];

export default function ApplyPage() {
  const [sceneIdx, setSceneIdx] = useState(0);
  const [inputIdx, setInputIdx] = useState(0);
  const [inputVal, setInputVal] = useState("");
  const [done, setDone] = useState<boolean[]>([false, false, false]);
  const [showAnim, setShowAnim] = useState(false);
  const [encourage, setEncourage] = useState("");
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);

  const inputRef = useRef<HTMLInputElement>(null);
  const activeWrapRef = useRef<HTMLDivElement>(null);

  const scene = SCENES[sceneIdx];
  const allDone = done.every(Boolean);

  const handleAnswer = useCallback(() => {
    const cur = scene.inputs[inputIdx];
    const val = parseInt(inputVal, 10);
    if (Number.isNaN(val)) return;
    if (val === cur.answer) {
      setEncourage("");
      setInputVal("");
      if (inputIdx + 1 < scene.inputs.length) {
        setInputIdx(inputIdx + 1);
        setTimeout(() => inputRef.current?.focus(), 60);
      } else {
        setShowAnim(true);
        setTimeout(() => {
          const nextDone = [...done];
          nextDone[sceneIdx] = true;
          setDone(nextDone);
          setShowAnim(false);
          setInputIdx(0);
          if (sceneIdx < SCENES.length - 1) {
            setSceneIdx((p) => p + 1);
          }
        }, 1600);
      }
    } else {
      triggerShake(activeWrapRef.current);
      setEncourage(getRandomEncourage());
      setInputVal("");
    }
  }, [scene, inputIdx, inputVal, done, sceneIdx]);

  return (
    <StepShell topicId="calendar" stepId="apply">
      <div className="space-y-6">
        {/* 场景进度 */}
        {!allDone && (
          <div className="flex justify-center gap-2">
            {SCENES.map((s, i) => (
              <div
                key={s.id}
                className={`flex-1 max-w-[90px] rounded-full px-3 py-1.5 text-center text-xs font-medium transition-all ${
                  done[i]
                    ? "bg-[var(--signal-success)] text-white"
                    : i === sceneIdx
                      ? "bg-[var(--signal-focus)] text-[var(--text)]"
                      : "bg-[var(--bg-soft)] text-[var(--text-muted)]"
                }`}
              >
                {s.icon} {s.title}
                {done[i] && <span className="ml-1">✓</span>}
              </div>
            ))}
          </div>
        )}

        {/* 当前场景 */}
        {!allDone && (
          <section
            key={scene.id}
            className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]"
          >
            {/* 场景插图 */}
            <div className="relative">
              {scene.svg}
              {showAnim && (
                <div className="pointer-events-none absolute inset-0 flex items-center justify-center">
                  <span className="animate-bounce-soft text-5xl">✨</span>
                </div>
              )}
            </div>

            {/* 题目 */}
            <div className="mt-3 text-center">
              <span className="inline-flex items-center gap-1 rounded-full bg-[var(--bg-soft)] px-3 py-1 text-xs font-medium text-[var(--text-secondary)]">
                {scene.icon} 场景 {sceneIdx + 1} / {SCENES.length}
              </span>
              <p className="mt-3 text-base font-medium text-[var(--text)]">{scene.question}</p>
            </div>

            {/* 引导计算 */}
            <div className="mt-5 rounded-[var(--radius-sm)] border border-dashed border-[var(--border)] bg-[var(--bg-soft)] p-4">
              <p className="mb-2 text-center text-xs font-medium text-[var(--text-muted)]">
                一步一步算一算
              </p>
              <div className="grid gap-2 sm:grid-cols-2">
                {scene.guide.map((g, i) => (
                  <div
                    key={i}
                    className="flex items-center gap-2 rounded-lg bg-[var(--bg-card)] px-3 py-2 text-sm"
                  >
                    <span className="shrink-0 rounded-md bg-[var(--primary)]/15 px-2 py-0.5 text-xs font-bold text-[var(--primary)]">
                      {g.label}
                    </span>
                    <span className="font-medium text-[var(--text)]">{g.expr}</span>
                  </div>
                ))}
              </div>
            </div>

            {/* 分步输入 */}
            <div className="mt-6 space-y-3">
              <p className="text-center text-sm text-[var(--text-secondary)]">
                把每一步的结果填进去（第 {inputIdx + 1} / {scene.inputs.length} 步）
              </p>

              {scene.inputs.map((inp, i) => {
                const isDone = i < inputIdx;
                const isActive = i === inputIdx;
                const isFuture = i > inputIdx;
                return (
                  <div
                    key={i}
                    className={`flex flex-wrap items-center justify-center gap-3 rounded-xl border-2 px-4 py-3 transition-all ${
                      isDone
                        ? "border-[var(--signal-success)] bg-[var(--signal-success)]/10"
                        : isActive
                          ? "border-[var(--signal-focus)] bg-[var(--signal-focus)]/10"
                          : "border-dashed border-[var(--border)] bg-[var(--bg-soft)] opacity-60"
                    }`}
                  >
                    <span className="text-sm font-medium text-[var(--text-secondary)]">
                      {inp.label}
                    </span>

                    {isDone && (
                      <span className="flex items-center gap-2 text-lg font-bold text-[var(--signal-success)]">
                        <span className="flex h-6 w-6 items-center justify-center rounded-full bg-[var(--signal-success)] text-xs text-white">
                          ✓
                        </span>
                        {inp.answer} {inp.unit}
                      </span>
                    )}

                    {isActive && (
                      <div ref={activeWrapRef} className="flex items-center gap-2">
                        <input
                          ref={inputRef}
                          type="text"
                          inputMode="numeric"
                          value={inputVal}
                          onChange={(e) => setInputVal(e.target.value.replace(/[^0-9]/g, ""))}
                          onKeyDown={(e) => e.key === "Enter" && handleAnswer()}
                          className="w-24 rounded-lg border-2 border-[var(--border)] px-3 py-2 text-center text-2xl font-bold text-[var(--text)] focus:border-[var(--primary)] focus:outline-none"
                          placeholder="?"
                          autoFocus
                        />
                        <span className="text-[var(--text-secondary)]">{inp.unit}</span>
                        <button
                          onClick={handleAnswer}
                          disabled={!inputVal}
                          className="rounded-full bg-[var(--primary)] px-5 py-2 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5 disabled:cursor-not-allowed disabled:opacity-40 disabled:hover:translate-y-0"
                        >
                          确定
                        </button>
                      </div>
                    )}

                    {isFuture && (
                      <span className="text-lg font-bold text-[var(--text-muted)]">? {inp.unit}</span>
                    )}
                  </div>
                );
              })}

              {/* 鼓励提示（橙色，非红色） */}
              {encourage && (
                <p className="text-center text-sm text-[var(--signal-shake)]">{encourage}</p>
              )}
            </div>
          </section>
        )}

        {/* 全部完成卡片 */}
        {allDone && (
          <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-8 text-center shadow-[var(--shadow-md)]">
            <div className="text-5xl animate-bounce-soft">🎉</div>
            <h2 className="mt-4 text-xl font-bold text-[var(--text)]">{completeMsg}</h2>
            <p className="mt-2 text-sm text-[var(--text-secondary)]">
              你算出了暑假、生日倒计时和一学期的天数，日期间隔难不倒你！
            </p>

            <div className="mt-5 flex flex-wrap justify-center gap-3">
              {SCENES.map((s) => (
                <span
                  key={s.id}
                  className="inline-flex items-center gap-1.5 rounded-full bg-[var(--bg-soft)] px-3 py-1 text-xs text-[var(--text-secondary)]"
                >
                  <span className="text-[var(--signal-success)]">✓</span>
                  {s.icon} {s.title}
                </span>
              ))}
            </div>

            <div className="mt-6 flex flex-wrap items-center justify-center gap-3">
              <Link
                href="/learn/calendar"
                className="rounded-full border border-[var(--border)] bg-[var(--bg-soft)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-card)]"
              >
                ← 回到年月日主页
              </Link>
              <Link
                href="/learn/calendar/discover"
                className="rounded-full bg-[var(--accent)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5"
              >
                下一步：发现年月日规律 →
              </Link>
            </div>
          </section>
        )}
      </div>
    </StepShell>
  );
}
